import { createClient } from '@supabase/supabase-js';

const app = document.querySelector('#app');
const config = window.INFINITY_CMS_CONFIG || {};
const configured = /^https:\/\/.+\.supabase\.co$/.test(config.supabaseUrl || '') && Boolean(config.supabaseAnonKey);
const supabase = configured ? createClient(config.supabaseUrl, config.supabaseAnonKey, {
  auth:{ persistSession:true, autoRefreshToken:true, detectSessionInUrl:true },
  global:{ headers:{ 'x-application-name':'infinity-cms' } }
}) : null;
const state = { session:null, profile:null, route:'dashboard', editId:null, lang:'en', cache:new Map() };
const routes = [
  ['dashboard','01','Dashboard'],['pages','02','Pages'],['home','03','Home'],['about','04','About'],['services','05','Services'],
  ['projects','06','Work / Projects'],['media','07','Media Library'],['navigation','08','Navigation'],['footer','09','Footer'],
  ['theme','10','Theme & Design'],['languages','11','Languages'],['seo','12','SEO'],['users','13','Admin Users'],
  ['settings','14','Website Settings'],['activity','15','Activity Log'],['guide','16','Help & Guide']
];
const ownerOnlyRoutes = new Set(['users','activity']);
const titles = Object.fromEntries(routes.map(r => [r[0],r[2]]));
const esc = value => String(value ?? '').replace(/[&<>'"]/g, char => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]));
const slugify = value => String(value || '').toLowerCase().trim().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
const publicUrl = (config.publicSiteUrl || location.origin).replace(/\/$/,'');

function setupView() {
  app.innerHTML = `<main class="setup-shell"><section class="setup-card"><div class="brand"><img src="../assets/images/brand/infinity-logo.png" alt=""><span><b>INfinity CMS</b><small>SECURE SETUP</small></span></div><p class="eyebrow">Configuration required</p><h1>Connect Supabase</h1><p>The CMS files are ready, but no database credentials are present. Copy <code>.env.example</code> to <code>.env</code>, add the project URL and public anon key, apply the SQL migration, then run the production build.</p><div class="danger-note">Never use the Supabase service-role key here. It belongs only in Edge Function secrets.</div><a class="btn btn-primary" href="../CMS-README.md">Open setup manual</a></section></main>`;
}

function authView(mode='login') {
  const reset = mode === 'reset';
  app.innerHTML = `<main class="auth-shell"><form class="auth-card" id="auth-form"><div class="brand"><img src="../assets/images/brand/infinity-logo.png" alt=""><span><b>INfinity Design Studio</b><small>CONTENT MANAGEMENT</small></span></div><p class="eyebrow">Administrator access</p><h1>${reset ? 'Reset password' : 'Welcome back'}</h1><p>${reset ? 'Email recovery is available for administrators created later with a real email address.' : 'Sign in with Owner, Admin 2, Admin 3, or an administrator email.'}</p><label class="field"><span>${reset?'Email address':'Username or email'}</span><input name="email" type="text" autocomplete="username" required></label>${reset ? '' : '<label class="field"><span>Password</span><input name="password" type="password" autocomplete="current-password" minlength="8" required></label>'}<button class="btn btn-primary" type="submit">${reset ? 'Send reset link' : 'Sign in securely'}</button><p class="message" id="auth-message"></p><button class="link-button" type="button" id="auth-switch">${reset ? 'Back to sign in' : 'Forgot password?'}</button></form></main>`;
  const form = document.querySelector('#auth-form');
  document.querySelector('#auth-switch').onclick = () => authView(reset ? 'login' : 'reset');
  form.onsubmit = async event => {
    event.preventDefault();
    const message = document.querySelector('#auth-message');
    const button = form.querySelector('button[type=submit]');
    button.disabled = true; message.className='message'; message.textContent='Please wait…';
    const values = new FormData(form);
    if (!reset) {
      const lockUntil = Number(localStorage.getItem('infinity-cms-lock-until') || 0);
      if (Date.now() < lockUntil) { message.className='message error'; message.textContent='Too many attempts. Try again in a few minutes.'; button.disabled=false; return; }
      const entered=String(values.get('email')).trim(), password=String(values.get('password'));
      let error=null;
      try{
        const response=await fetch(`${config.supabaseUrl}/functions/v1/admin-users`,{method:'POST',headers:{apikey:config.supabaseAnonKey,'Content-Type':'application/json','x-client-info':'infinity-cms'},body:JSON.stringify({action:'sign-in',identifier:entered,password})});
        const data=await response.json();
        if(!response.ok||!data.access_token||!data.refresh_token)throw new Error('Sign in failed');
        const result=await supabase.auth.setSession({access_token:data.access_token,refresh_token:data.refresh_token});
        error=result.error;
      }catch(signInError){error=signInError}
      if (error) {
        const attempts = Number(localStorage.getItem('infinity-cms-attempts') || 0) + 1;
        localStorage.setItem('infinity-cms-attempts',String(attempts));
        if (attempts >= 5) { localStorage.setItem('infinity-cms-lock-until',String(Date.now()+5*60*1000)); localStorage.removeItem('infinity-cms-attempts'); }
        message.className='message error'; message.textContent='Sign in failed. Check your details or reset your password.'; button.disabled=false;
      } else { localStorage.removeItem('infinity-cms-attempts'); localStorage.removeItem('infinity-cms-lock-until'); }
    } else {
      const { error } = await supabase.auth.resetPasswordForEmail(String(values.get('email')), { redirectTo:`${location.origin}${location.pathname}` });
      message.className=`message ${error?'error':'success'}`; message.textContent=error ? error.message : 'Reset link sent. Check your inbox.'; button.disabled=false;
    }
  };
}

async function loadProfile() {
  const { data, error } = await supabase.from('admin_users').select('user_id,username,email,display_name,role,is_active,last_login_at,last_ip').eq('user_id',state.session.user.id).maybeSingle();
  if (error || !data?.is_active) { await supabase.auth.signOut(); return false; }
  state.profile = data;
  adminRequest('session').catch(()=>{});
  return true;
}

function shell() {
  app.innerHTML = `<div class="cms"><aside class="sidebar" id="sidebar"><div class="brand"><img src="../assets/images/brand/infinity-logo.png" alt=""><span><b>INfinity CMS</b><small>${esc(state.profile.role)}</small></span></div><nav class="nav-group">${routes.filter(([key])=>state.profile.role==='owner'||!ownerOnlyRoutes.has(key)).map(([key,num,label])=>`<a class="nav-link" data-route="${key}" href="#${key}"><span>${num}</span>${key==='users'?'User Management':label}</a>`).join('')}</nav><div class="sidebar-footer"><div class="user-chip"><b>${esc(state.profile.display_name)}</b><small>${esc(state.session.user.email)}</small></div><button class="btn" id="change-password">Change my password</button> <button class="btn" id="logout">Log out</button></div></aside><main class="main"><header class="topbar"><button class="menu-button" id="menu" aria-label="Open menu">☰</button><p class="eyebrow">${esc(titles[state.route] || 'Dashboard')}</p><div class="top-actions"><a class="btn" href="${esc(publicUrl)}" target="_blank" rel="noopener">Preview website ↗</a><button class="btn btn-primary" id="quick-project">+ New project</button></div></header><div class="content" id="content"></div></main></div>`;
  document.querySelector('#logout').onclick = () => supabase.auth.signOut();
  document.querySelector('#change-password').onclick = passwordModal;
  document.querySelector('#menu').onclick = () => document.querySelector('#sidebar').classList.toggle('open');
  document.querySelector('#quick-project').onclick = () => navigate('projects','new');
  document.querySelectorAll('[data-route]').forEach(link => link.onclick = () => document.querySelector('#sidebar').classList.remove('open'));
  renderRoute();
}
function passwordModal(){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Change password</h2><button class="close" type="button">×</button></div>${field('New password','password','','password','minlength="12" autocomplete="new-password" required')}${field('Confirm password','confirm','','password','minlength="12" autocomplete="new-password" required')}<button class="btn btn-primary">Update password</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),password=String(f.get('password'));if(password!==f.get('confirm'))return toast('Passwords do not match.',true);const{error}=await supabase.auth.updateUser({password});if(error)return toast(error.message,true);modal.remove();toast('Password updated')}}

function navigate(route,id=null) { state.editId=id; location.hash=id?`${route}/${id}`:route; }
function parseRoute() { const [route='dashboard',id=null] = location.hash.replace(/^#/,'').split('/'); state.route=titles[route]?route:'dashboard'; if(state.profile?.role!=='owner'&&ownerOnlyRoutes.has(state.route))state.route='dashboard'; state.editId=id; }
function head(title,description,action='') { return `<header class="page-head"><div><p class="eyebrow">INFINITY / CMS</p><h1>${esc(title)}</h1><p>${esc(description)}</p></div>${action}</header>`; }
function toast(message,error=false) { const el=document.createElement('div'); el.className=`toast${error?' error':''}`; el.textContent=message; document.body.append(el); setTimeout(()=>el.remove(),3500); }
function loading() { document.querySelector('#content').innerHTML='<div class="empty">Loading secure content…</div>'; }
async function query(table,select='*',options={}) {
  let request=supabase.from(table).select(select);
  if (options.order) request=request.order(options.order,{ascending:options.ascending!==false});
  if (options.eq) for (const [key,value] of Object.entries(options.eq)) request=request.eq(key,value);
  if (options.is) for (const [key,value] of Object.entries(options.is)) request=request.is(key,value);
  const {data,error}=await request; if(error) throw error; return data||[];
}
const fieldHints={
  'Page title':'The main page name shown to visitors and search engines.','Description':'The short summary used on the website and by search engines.',
  'Slug':'The safe URL name. Use lowercase letters, numbers and hyphens only.','Service title':'The service name visitors see.',
  'Project title':'The project name shown in the portfolio.','Short description':'A concise summary shown before the full project content.',
  'Category':'Controls which service category contains this item.','Service':'Controls which service page displays this project.',
  'View Project URL':'The public link opened by the View Project button.','Order':'Lower numbers appear first.',
  'Status':'Draft is private. Published content is visible on the live website.','Publish date':'The date used to order published projects.',
  'Featured project':'Highlights this project where featured work is supported.','Year':'The project year shown to visitors.',
  'Studio name':'The business name shown in shared website settings.','Contact email':'The email address used by website contact links.',
  'WhatsApp URL':'The destination opened by the WhatsApp button.','Default language':'The website language shown first to new visitors.',
  'Website status':'Maintenance hides normal public access; Live keeps the website available.'
};
function hintFor(label){return fieldHints[label]||`Controls the ${String(label).toLowerCase()} used by the website.`}
function fieldLabel(label){const hint=hintFor(label);return `<span>${esc(label)} <button class="field-help" type="button" title="${esc(hint)}" aria-label="Help: ${esc(label)}">?</button></span>`}
function field(label,name,value='',type='text',extra='') { return `<label class="field">${fieldLabel(label)}<input name="${esc(name)}" type="${type}" value="${esc(value)}" ${extra}></label>`; }
function area(label,name,value='') { return `<label class="field">${fieldLabel(label)}<textarea name="${esc(name)}">${esc(value)}</textarea></label>`; }
function selectField(label,name,value,items) { return `<label class="field">${fieldLabel(label)}<select name="${esc(name)}">${items.map(item=>`<option value="${esc(item[0])}" ${item[0]===value?'selected':''}>${esc(item[1])}</option>`).join('')}</select></label>`; }
function languageTabs() { return `<div class="tabs" role="tablist" aria-label="Content language"><button class="tab ${state.lang==='en'?'active':''}" type="button" role="tab" aria-selected="${state.lang==='en'}" data-lang="en">English</button><button class="tab ${state.lang==='zh'?'active':''}" type="button" role="tab" aria-selected="${state.lang==='zh'}" data-lang="zh">中文（简体）</button></div>`; }
function bindLanguageTabs(render) { document.querySelectorAll('[data-lang]').forEach(btn=>btn.onclick=()=>{state.lang=btn.dataset.lang;render();}); }
async function saveRow(table,payload,id) {
  payload.updated_by = ['pages','projects','theme_settings','site_settings','seo_settings'].includes(table) ? state.profile.user_id : payload.updated_by;
  Object.keys(payload).forEach(key=>payload[key]===undefined&&delete payload[key]);
  const request=id&&id!=='new'?supabase.from(table).update(payload).eq('id',id).select().single():supabase.from(table).insert(payload).select().single();
  const {data,error}=await request;if(error)throw error;return data;
}

async function dashboard() {
  loading();
  const [projects,media,pages,logs]=await Promise.all([
    query('projects','id,status',{is:{deleted_at:null}}),query('media','id',{is:{deleted_at:null}}),query('pages','id,status',{is:{deleted_at:null}}),state.profile.role==='owner'?query('activity_logs','action,entity_table,created_at',{order:'created_at',ascending:false}).then(v=>v.slice(0,6)):Promise.resolve([])
  ]);
  const published=[...projects,...pages].filter(x=>x.status==='published').length,drafts=[...projects,...pages].filter(x=>x.status==='draft').length;
  document.querySelector('#content').innerHTML=head('Dashboard','Website status and recent publishing activity.')+`<section class="stats"><article class="stat"><span>Website</span><b>Live</b></article><article class="stat"><span>Projects</span><b>${projects.length}</b></article><article class="stat"><span>Media</span><b>${media.length}</b></article><article class="stat"><span>Draft / Published</span><b>${drafts} / ${published}</b></article></section><div class="grid-2"><section class="panel"><h2>Recent activity</h2>${logs.length?logs.map(log=>`<div class="log"><time>${new Date(log.created_at).toLocaleString()}</time><span>${esc(log.action)}</span><b>${esc(log.entity_table||'system')}</b></div>`).join(''):'<div class="empty">No activity yet.</div>'}</section><section class="panel"><h2>Quick actions</h2><div class="records"><button class="btn btn-primary" data-new-project>+ Add a project</button><a class="btn" href="#media">Upload media</a><a class="btn" href="${esc(publicUrl)}" target="_blank" rel="noopener">Open live website ↗</a></div></section></div>`;
  document.querySelector('[data-new-project]').onclick=()=>navigate('projects','new');
}

const pageRouteFilter={home:'home',about:'about'};
async function pages(route='pages') {
  if(state.editId) return pageEditor(); loading();
  let rows=await query('pages','id,slug,title_en,title_zh,status,updated_at',{order:'updated_at',ascending:false,is:{deleted_at:null}});
  if(pageRouteFilter[route]) rows=rows.filter(row=>row.slug===pageRouteFilter[route]);
  document.querySelector('#content').innerHTML=head(titles[route],route==='pages'?'Manage safe, structured bilingual page content.':'Edit the existing page without touching source code.',`<button class="btn btn-primary" data-new>+ New page</button>`)+`<div class="toolbar"><input class="search" type="search" placeholder="Search pages…"></div><div class="records">${rows.length?rows.map(row=>`<article class="record-card" data-search="${esc(`${row.title_en} ${row.title_zh}`.toLowerCase())}"><div class="record-main"><b>${esc(state.lang==='zh'?row.title_zh:row.title_en)}</b><small>/${esc(row.slug)} · <span class="pill ${esc(row.status)}">${esc(row.status)}</span></small></div><div class="record-actions"><button class="btn" data-edit="${row.id}">Edit</button><a class="btn" href="${publicUrl}/${row.slug==='home'?'':`${row.slug}/`}" target="_blank">Preview</a></div></article>`).join(''):'<div class="empty">No CMS pages yet. Existing static pages remain unchanged.</div>'}</div>`;
  document.querySelector('[data-new]').onclick=()=>navigate('pages','new');
  document.querySelectorAll('[data-edit]').forEach(btn=>btn.onclick=()=>navigate(route,btn.dataset.edit));
  const search=document.querySelector('.search');search.oninput=()=>document.querySelectorAll('[data-search]').forEach(row=>row.hidden=!row.dataset.search.includes(search.value.toLowerCase()));
}

async function pageEditor() {
  loading(); const isNew=state.editId==='new';
  const row=isNew?{slug:'',title_en:'',title_zh:'',description_en:'',description_zh:'',status:'draft'}:(await query('pages','*',{eq:{id:state.editId}}))[0];
  if(!row){toast('Page not found',true);return navigate('pages');}
  const sections=isNew?[]:await query('page_sections','*',{eq:{page_id:row.id},order:'sort_order'});
  const render=()=>{
    const lang=state.lang;
    document.querySelector('#content').innerHTML=head(isNew?'New Page':`Edit ${row.title_en}`,'Draft changes are private until published.',`<button class="btn" data-back>← Back</button>`)+`<form id="page-form" class="editor"><div class="editor-main"><section class="panel">${languageTabs()}<div class="form-grid">${field('Page title',`title_${lang}`,row[`title_${lang}`]||'')}${area('Description',`description_${lang}`,row[`description_${lang}`]||'')}</div></section><section class="panel"><div class="toolbar"><h2>Page sections</h2><button class="btn" type="button" data-add-section>+ Add section</button></div><div class="section-list" id="section-list">${sections.length?sections.map(s=>`<div class="section-item" draggable="true" data-section="${s.id}"><div><b>${esc(s[`title_${lang}`]||s.section_key)}</b><small class="pill">${esc(s.section_type)}</small></div><button class="btn" type="button" data-section-edit="${s.id}">Edit</button></div>`).join(''):'<div class="empty">No structured sections yet.</div>'}</div></section></div><aside class="editor-side"><section class="panel"><h2>Publishing</h2>${selectField('Status','status',row.status,[['draft','Draft'],['published','Published'],['hidden','Hidden'],['archived','Archived']])}<button class="btn btn-primary" type="submit">${row.status==='published'?'Update published page':'Save page'}</button></section><section class="panel"><h2>URL</h2>${field('Slug','slug',row.slug,'text','pattern="[a-z0-9-]+" required')}<p class="message">Safe lowercase URL characters only.</p></section></aside></form>`;
    bindLanguageTabs(render);document.querySelector('[data-back]').onclick=()=>navigate(state.route);
    document.querySelector('#page-form').onsubmit=async e=>{e.preventDefault();const fd=new FormData(e.currentTarget);const payload={slug:slugify(fd.get('slug')),status:fd.get('status'),[`title_${lang}`]:fd.get(`title_${lang}`),[`description_${lang}`]:fd.get(`description_${lang}`)};if(!isNew){payload[`title_${lang==='en'?'zh':'en'}`]=row[`title_${lang==='en'?'zh':'en'}`];payload[`description_${lang==='en'?'zh':'en'}`]=row[`description_${lang==='en'?'zh':'en'}`];}else{payload.title_en=lang==='en'?fd.get('title_en'):'Untitled';payload.title_zh=lang==='zh'?fd.get('title_zh'):'未命名';}try{const saved=await saveRow('pages',payload,isNew?null:row.id);toast('Page saved');navigate('pages',saved.id);}catch(error){toast(error.message,true)}};
    document.querySelector('[data-add-section]').onclick=()=>openSectionModal(null,row,sections,render);
    document.querySelectorAll('[data-section-edit]').forEach(btn=>btn.onclick=()=>openSectionModal(sections.find(s=>s.id===btn.dataset.sectionEdit),row,sections,render));
    bindDragList(document.querySelector('#section-list'),async ids=>{for(let i=0;i<ids.length;i++)await supabase.from('page_sections').update({sort_order:i}).eq('id',ids[i]);toast('Section order saved')});
  };render();
}

function openSectionModal(section,page,sections,rerender) {
  if(!page.id){toast('Save the page before adding sections.',true);return;}
  const current=section||{section_key:`section-${sections.length+1}`,section_type:'text',title_en:'',title_zh:'',content_en:{text:''},content_zh:{text:''},is_visible:true};
  const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>${section?'Edit':'Add'} section</h2><button class="close" type="button">×</button></div>${field('Internal key','section_key',current.section_key)}${selectField('Preset layout','section_type',current.section_type,[['hero','Hero Banner'],['text','Text Block'],['image-text','Image + Text'],['full-image','Full-width Image'],['two-column','Two Columns'],['three-column','Three Columns'],['image-grid','Image Grid'],['project-cards','Project Cards'],['cta','Call To Action'],['spacer','Spacer'],['divider','Divider'],['gallery','Gallery']])}${field('English title','title_en',current.title_en)}${field('中文标题','title_zh',current.title_zh)}${area('English text','text_en',current.content_en?.text||'')}${area('中文内容','text_zh',current.content_zh?.text||'')}<label class="field"><span><input type="checkbox" name="is_visible" ${current.is_visible?'checked':''}> Visible</span></label><button class="btn btn-primary" type="submit">Save section</button>${section?'<button class="btn btn-danger" type="button" data-delete>Delete section</button>':''}</form>`;document.body.append(modal);
  modal.querySelector('.close').onclick=()=>modal.remove();modal.onclick=e=>{if(e.target===modal)modal.remove()};
  modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);const payload={page_id:page.id,section_key:slugify(f.get('section_key')),section_type:f.get('section_type'),title_en:f.get('title_en'),title_zh:f.get('title_zh'),content_en:{text:f.get('text_en')},content_zh:{text:f.get('text_zh')},is_visible:f.get('is_visible')==='on',sort_order:section?.sort_order??sections.length};const {data,error}=section?await supabase.from('page_sections').update(payload).eq('id',section.id).select().single():await supabase.from('page_sections').insert(payload).select().single();if(error)return toast(error.message,true);if(section)Object.assign(section,data);else sections.push(data);modal.remove();toast('Section saved');rerender()};
  if(section)modal.querySelector('[data-delete]').onclick=async()=>{if(!confirm('Delete this section? This action is recorded in version history.'))return;const{error}=await supabase.from('page_sections').delete().eq('id',section.id);if(error)return toast(error.message,true);sections.splice(sections.indexOf(section),1);modal.remove();rerender()};
}

function bindDragList(container,onSave){if(!container)return;let dragged;container.querySelectorAll('[draggable=true]').forEach(item=>{item.ondragstart=()=>{dragged=item;item.classList.add('dragging')};item.ondragend=async()=>{item.classList.remove('dragging');await onSave([...container.querySelectorAll('[data-section]')].map(x=>x.dataset.section))};item.ondragover=e=>{e.preventDefault();if(!dragged||dragged===item)return;const box=item.getBoundingClientRect();container.insertBefore(dragged,e.clientY<box.top+box.height/2?item:item.nextSibling)}})}

async function services() {
  if(state.editId)return serviceEditor();loading();
  const rows=await query('services','id,slug,title_en,title_zh,status,is_visible,project_url,service_categories(title_en,title_zh)',{order:'sort_order',is:{deleted_at:null}});
  document.querySelector('#content').innerHTML=head('Services','Manage the existing service taxonomy and project destinations.',`<button class="btn btn-primary" data-new>+ New service</button>`)+`<div class="records">${rows.map(row=>`<article class="record-card"><div class="record-main"><b>${esc(row.title_en)} / ${esc(row.title_zh)}</b><small>${esc(row.service_categories?.title_en||'')} · <span class="pill ${row.status}">${row.status}</span> · ${row.is_visible?'Visible':'Hidden'}</small></div><div class="record-actions"><button class="btn" data-edit="${row.id}">Edit</button><a class="btn" href="${esc(publicUrl+row.project_url)}" target="_blank">View</a></div></article>`).join('')}</div>`;
  document.querySelector('[data-new]').onclick=()=>navigate('services','new');document.querySelectorAll('[data-edit]').forEach(btn=>btn.onclick=()=>navigate('services',btn.dataset.edit));
}
