async function adminRequest(action,payload={}){const{data:{session}}=await supabase.auth.getSession();if(!session)throw new Error('Your administrator session has expired.');const response=await fetch(`${config.supabaseUrl}/functions/v1/admin-users`,{method:'POST',headers:{apikey:config.supabaseAnonKey,Authorization:`Bearer ${session.access_token}`,'Content-Type':'application/json','x-client-info':'infinity-cms'},body:JSON.stringify({action,...payload})});let data={};try{data=await response.json()}catch{}if(!response.ok)throw new Error(data.error||`Administrator service returned ${response.status}`);return data}
async function users(){
  loading();
  if(state.profile.role!=='owner'){document.querySelector('#content').innerHTML=head('User Management','Owner access is required.')+'<div class="empty">Editors cannot access administrator records or management actions.</div>';return}
  const rows=(await adminRequest('list')).users||[];
  document.querySelector('#content').innerHTML=head('User Management','Owner-only account controls, security status and activity history.',`<button class="btn btn-primary" data-create-admin>+ Create administrator</button>`)+`<div class="records">${rows.map(r=>{const protectedOwner=r.username==='owner',lastActivity=r.history?.[0]?.created_at;return `<article class="record-card"><div class="record-main"><b>${esc(r.display_name)} <span class="pill">${esc(r.role)}</span> <span class="pill ${r.is_active?'published':'archived'}">${r.is_active?'Active':'Disabled'}</span></b><small>Username: <strong>${esc(r.username)}</strong> · Email: <strong>${esc(r.email||'Unavailable')}</strong></small><small>Created: ${r.created_at?new Date(r.created_at).toLocaleString():'Unknown'} · Last login: ${r.last_sign_in_at?new Date(r.last_sign_in_at).toLocaleString():'Never'}</small><small>Last activity: ${lastActivity?new Date(lastActivity).toLocaleString():'Never'} · Last IP: ${esc(r.last_ip||'Not recorded')}</small><details><summary>Activity history (${r.history?.length||0})</summary>${(r.history||[]).map(log=>`<div class="log"><time>${new Date(log.created_at).toLocaleString()}</time><span>${esc(log.action)}</span><b>${esc(log.entity_table||'authentication')}</b></div>`).join('')||'<div class="empty">No activity recorded.</div>'}</details></div><div class="record-actions"><button class="btn" data-edit-admin="${r.user_id}">Edit</button><button class="btn" data-reset-admin="${r.user_id}">Reset password</button>${protectedOwner?'':`<button class="btn" data-toggle-admin="${r.user_id}">${r.is_active?'Disable':'Enable'}</button><button class="btn btn-danger" data-delete-admin="${r.user_id}">Delete</button>`}</div></article>`}).join('')}</div>`;
  const byId=id=>rows.find(row=>row.user_id===id);
  document.querySelector('[data-create-admin]').onclick=()=>openCreateAdmin();
  document.querySelectorAll('[data-edit-admin]').forEach(button=>button.onclick=()=>openEditAdmin(byId(button.dataset.editAdmin)));
  document.querySelectorAll('[data-reset-admin]').forEach(button=>button.onclick=()=>openAdminPassword(byId(button.dataset.resetAdmin)));
  document.querySelectorAll('[data-toggle-admin]').forEach(button=>button.onclick=async()=>{const row=byId(button.dataset.toggleAdmin);if(row.is_active&&!confirm(`Disable ${row.display_name}? Their CMS access will stop immediately.`))return;try{await adminRequest('update',{userId:row.user_id,displayName:row.display_name,email:row.email,role:row.role,isActive:!row.is_active});toast(row.is_active?'Administrator disabled':'Administrator enabled');users()}catch(error){toast(error.message,true)}});
  document.querySelectorAll('[data-delete-admin]').forEach(button=>button.onclick=()=>openDeleteAdmin(byId(button.dataset.deleteAdmin)));
}
function openCreateAdmin(){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Create administrator</h2><button class="close" type="button">×</button></div>${field('Full name','displayName','Editor','text','required')}${field('Username','username','','text','pattern="[a-z0-9-]{3,32}" required')}${field('Login email','email','','email','required')}${field('Password','password','','password','minlength="12" autocomplete="new-password" required')}${field('Confirm password','confirm','','password','minlength="12" autocomplete="new-password" required')}${selectField('Role','role','editor',[['editor','Editor'],['owner','Owner']])}<label class="field"><span><input name="isActive" type="checkbox" checked> Account active</span></label><button class="btn btn-primary">Create account</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);if(f.get('password')!==f.get('confirm'))return toast('Passwords do not match.',true);try{await adminRequest('create',{username:f.get('username'),displayName:f.get('displayName'),email:f.get('email'),role:f.get('role'),password:f.get('password'),isActive:f.get('isActive')==='on'});modal.remove();toast('Administrator created');users()}catch(error){toast(error.message,true)}}}
function openEditAdmin(row){const protectedOwner=row.username==='owner';const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Edit ${esc(row.display_name)}</h2><button class="close" type="button">×</button></div>${field('Display name','displayName',row.display_name,'text','required')}${field('Username','username',row.username,'text',protectedOwner?'readonly':'pattern="[a-z0-9-]{3,32}" required')}${field('Login email','email',row.email,'email','required')}${protectedOwner?'<div class="danger-note">The Owner username, role and active status are permanently protected.</div>':selectField('Role','role',row.role,[['editor','Editor'],['owner','Owner']])}<button class="btn btn-primary">Save administrator</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);try{await adminRequest('update',{userId:row.user_id,username:f.get('username'),displayName:f.get('displayName'),email:f.get('email'),role:protectedOwner?'owner':f.get('role'),isActive:protectedOwner?true:row.is_active});modal.remove();toast('Administrator updated');users()}catch(error){toast(error.message,true)}}}
function openAdminPassword(row){const changingOther=row.user_id!==state.profile.user_id;const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Reset ${esc(row.display_name)} password</h2><button class="close" type="button">×</button></div><p class="danger-note">This immediately invalidates the administrator's existing password. The old password is never displayed.</p>${changingOther?field('Confirm your Owner password','ownerPassword','','password','autocomplete="current-password" required'):''}${field('New password','password','','password','minlength="12" autocomplete="new-password" required')}${field('Confirm new password','confirm','','password','minlength="12" autocomplete="new-password" required')}<button class="btn btn-primary">Reset password</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);if(f.get('password')!==f.get('confirm'))return toast('Passwords do not match.',true);if(!confirm(`Reset ${row.display_name}'s password now?`))return;try{await adminRequest('reset-password',{userId:row.user_id,password:f.get('password'),ownerPassword:f.get('ownerPassword')});modal.remove();toast('Password reset complete')}catch(error){toast(error.message,true)}}}
function openDeleteAdmin(row){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Delete ${esc(row.display_name)}</h2><button class="close" type="button">×</button></div><div class="danger-note">This permanently deletes the administrator's Supabase Auth account and CMS access. This cannot be undone.</div>${field('Confirm your Owner password','ownerPassword','','password','autocomplete="current-password" required')}<button class="btn btn-danger">Permanently delete account</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);if(!confirm(`Permanently delete ${row.display_name}?`))return;try{await adminRequest('delete',{userId:row.user_id,ownerPassword:f.get('ownerPassword')});modal.remove();toast('Administrator deleted');users()}catch(error){toast(error.message,true)}}}
async function activity(){if(state.profile.role!=='owner'){document.querySelector('#content').innerHTML=head('Activity Log','Owner access is required.')+'<div class="empty">Editors cannot view administrator activity logs.</div>';return}loading();const [rows,versions]=await Promise.all([query('activity_logs','id,action,entity_table,entity_id,metadata,created_at,admin_users(display_name)',{order:'created_at',ascending:false}),query('content_versions','id,entity_table,entity_id,operation,before_data,after_data,created_at,admin_users(display_name)',{order:'created_at',ascending:false})]);document.querySelector('#content').innerHTML=head('Activity Log','Traceable changes, publishing activity and recoverable versions.')+`<div class="grid-2"><section class="panel"><h2>Recent activity</h2>${rows.slice(0,100).map(r=>`<div class="log"><time>${new Date(r.created_at).toLocaleString()}</time><span>${esc(r.admin_users?.display_name||'System')}</span><b>${esc(r.action)} · ${esc(r.entity_table||'authentication')}</b></div>`).join('')||'<div class="empty">No activity recorded yet.</div>'}</section><section class="panel"><h2>Previous versions</h2>${versions.slice(0,50).map(v=>`<div class="record-card"><div class="record-main"><b>${esc(v.entity_table)} · ${esc(v.operation)}</b><small>${new Date(v.created_at).toLocaleString()}</small></div>${v.before_data&&['pages','projects'].includes(v.entity_table)?`<button class="btn" data-restore="${v.id}">Restore</button>`:''}</div>`).join('')||'<div class="empty">No versions yet.</div>'}</section></div>`;document.querySelectorAll('[data-restore]').forEach(button=>button.onclick=async()=>{const version=versions.find(v=>String(v.id)===button.dataset.restore);if(!version||!confirm('Restore this previous version? The current version will also be preserved.'))return;const payload={...version.before_data};delete payload.id;delete payload.created_at;delete payload.updated_at;const{error}=await supabase.from(version.entity_table).update(payload).eq('id',version.entity_id);if(error)return toast(error.message,true);toast('Previous version restored');activity()})}
function languages(){document.querySelector('#content').innerHTML=head('Languages','English and Simplified Chinese are first-class content fields.')+`<div class="grid-2"><section class="panel"><h2>English</h2><p>Primary locale: <b>en</b></p><p class="message">All Pages, Services, Projects, Navigation, Footer and SEO records include dedicated English fields.</p></section><section class="panel"><h2>中文（简体）</h2><p>语言代码：<b>zh-CN</b></p><p class="message">所有页面、服务、项目、导航、页脚和 SEO 内容均拥有独立中文字段。</p></section></div>`}

