function howToBox(route){const copy=guideCopy[route];if(!copy)return'';return `<aside class="how-to"><div class="how-to-icon">?</div><div><p class="eyebrow">How to use this page</p><h2>${esc(copy[0])}</h2><p>${esc(copy[1])}</p><a href="#guide">Open the complete beginner guide →</a></div></aside>`}
function workflowBar(previewUrl){return `<div class="workflow-bar" role="toolbar" aria-label="Editing actions"><button class="btn is-active" type="button" data-action="edit">Edit</button><button class="btn" type="button" data-action="draft">Save Draft</button><a class="btn" href="${esc(previewUrl)}" target="_blank" rel="noopener" data-action="preview">Preview</a><button class="btn btn-primary" type="button" data-action="publish">Publish</button><button class="btn" type="button" data-action="cancel">Cancel</button></div>`}
function livePageUrl(slug){const anchors={home:'home',about:'about',services:'services',work:'portfolio',contact:'contact'};return `${publicUrl}/#${anchors[slug]||slug}`}
function captureFields(form,row,names,lang){names.forEach(name=>{const input=form.elements[`${name}_${lang}`];if(input)row[`${name}_${lang}`]=input.value})}
function bindFriendlyLanguageTabs(render,capture){document.querySelectorAll('[data-lang]').forEach(button=>button.onclick=()=>{capture();state.lang=button.dataset.lang;render()})}
