async function uploadAsset(file){
  const allowed=new Set(['image/jpeg','image/png','image/webp','image/avif']);
  if(!file||!allowed.has(file.type)||file.size>10485760)throw new Error('Choose a JPG, PNG, WebP or AVIF image smaller than 10 MB.');
  const output=await optimizeImage(file),extension=output.blob.type==='image/webp'?'webp':file.name.split('.').pop().toLowerCase();
  const objectPath=`${state.profile.user_id}/${Date.now()}-${crypto.randomUUID()}.${extension}`;
  const{error:uploadError}=await supabase.storage.from('cms-media').upload(objectPath,output.blob,{contentType:output.blob.type,cacheControl:'31536000',upsert:false});
  if(uploadError)throw uploadError;
  const{data:url}=supabase.storage.from('cms-media').getPublicUrl(objectPath);
  const{data,error}=await supabase.from('media').insert({object_path:objectPath,public_url:url.publicUrl,original_name:file.name,mime_type:output.blob.type,size_bytes:output.blob.size,width:output.width||null,height:output.height||null,uploaded_by:state.profile.user_id}).select().single();
  if(error){await supabase.storage.from('cms-media').remove([objectPath]);throw error}return data;
}
function imageControl(media,label='Cover image'){return `<div class="image-control"><div class="image-preview">${media?.public_url?`<img src="${esc(media.public_url)}" alt="" loading="lazy">`:'<span>No image selected</span>'}</div><div><b>${esc(label)}</b><p>${media?'Upload a replacement or keep the current image.':'Upload a clear, optimized project image.'}</p><label class="btn">${media?'Replace image':'Upload image'}<input type="file" hidden data-cover-upload accept="image/jpeg,image/png,image/webp,image/avif"></label></div></div>`}

function openFriendlySectionModal(section,page,sections,rerender){
  if(!page.id)return toast('Save the page as a draft before adding sections.',true);
  const isNew=!section;let current=section?structuredClone(section):{_draftId:`draft-${crypto.randomUUID()}`,page_id:page.id,section_key:'new-section',section_type:'text',title_en:'',title_zh:'',content_en:{text:'',image_url:''},content_zh:{text:'',image_url:''},layout:{},sort_order:sections.length,is_visible:true};let lang='en';
  const render=()=>{const content=current[`content_${lang}`]||{};modal(isNew?'Add page section':'Edit page section',`${languageTabs()}${field('Section name',`title_${lang}`,current[`title_${lang}`]||'')}${area('Section text',`text_${lang}`,content.text||'')}<div class="image-control"><div class="image-preview">${content.image_url?`<img src="${esc(content.image_url)}" alt="" loading="lazy">`:'<span>No section image</span>'}</div><div><b>Section image</b><p>Upload a replacement image for this language.</p><label class="btn">${content.image_url?'Replace image':'Upload image'}<input type="file" hidden data-section-upload accept="image/jpeg,image/png,image/webp,image/avif"></label></div></div>${field('Internal section key','section_key',current.section_key)}${selectField('Section layout','section_type',current.section_type,[['text','Text'],['hero','Hero'],['image-text','Image and text'],['two-column','Two columns'],['three-column','Three columns'],['full-image','Full image'],['image-grid','Image grid'],['project-cards','Project cards'],['cta','Call to action'],['spacer','Spacer'],['divider','Divider'],['gallery','Gallery']])}<label class="field checkbox-field"><span><input name="is_visible" type="checkbox" ${current.is_visible?'checked':''}> Visible on website</span></label>`,{label:'Save section',class:'btn-primary',onClick:save});
    const form=document.querySelector('#modal-form');const capture=()=>{current[`title_${lang}`]=form.elements[`title_${lang}`]?.value||'';current[`content_${lang}`]={...(current[`content_${lang}`]||{}),text:form.elements[`text_${lang}`]?.value||''};current.section_key=slugify(form.elements.section_key.value)||'section';current.section_type=form.elements.section_type.value;current.is_visible=form.elements.is_visible.checked};
    document.querySelectorAll('[data-lang]').forEach(button=>button.onclick=()=>{capture();lang=button.dataset.lang;render()});
    form.querySelector('[data-section-upload]').onchange=async event=>{try{capture();const media=await uploadAsset(event.target.files[0]);current[`content_${lang}`]={...(current[`content_${lang}`]||{}),image_url:media.public_url,media_id:media.id};render();toast('Image uploaded. Save the section to keep it.')}catch(error){toast(error.message,true)}};
  };
  async function save(){const form=document.querySelector('#modal-form');current[`title_${lang}`]=form.elements[`title_${lang}`]?.value||'';current[`content_${lang}`]={...(current[`content_${lang}`]||{}),text:form.elements[`text_${lang}`]?.value||''};current.section_key=slugify(form.elements.section_key.value)||'section';current.section_type=form.elements.section_type.value;current.is_visible=form.elements.is_visible.checked;try{if(page._cmsDraftOnly){if(isNew)sections.push(current);else Object.assign(section,current);closeModal();success('Section change staged. Save Draft or Publish to keep it.');return rerender()}const saved=await saveRow('page_sections',current,section?.id);if(isNew)sections.push(saved);else Object.assign(section,saved);closeModal();success('Section saved.');rerender()}catch(error){toast(error.message,true)}}
  render();
}

async function friendlyPages(route='pages'){
  if(state.editId)return friendlyPageEditor(route);loading();
  let rows=await query('pages','id,slug,title_en,title_zh,status,updated_at',{order:'updated_at',ascending:false,is:{deleted_at:null}});
  if(pageRouteFilter[route]){rows=rows.filter(row=>row.slug===pageRouteFilter[route]);if(rows[0]){state.editId=rows[0].id;return friendlyPageEditor(route)}}
  document.querySelector('#content').innerHTML=head('Pages','Open a page to edit its current English and Chinese content.',`<button class="btn btn-primary" data-new>+ New page</button>`)+`<div class="records">${rows.map(row=>`<article class="record-card"><div class="record-main"><b>${esc(row.title_en)} / ${esc(row.title_zh)}</b><small>/${esc(row.slug)} · <span class="pill ${esc(row.status)}">${esc(row.status)}</span></small></div><div class="record-actions"><button class="btn" data-edit="${row.id}">Edit</button><a class="btn" href="${livePageUrl(row.slug)}" target="_blank">Preview</a></div></article>`).join('')}</div>`;
  document.querySelector('[data-new]').onclick=()=>navigate('pages','new');document.querySelectorAll('[data-edit]').forEach(button=>button.onclick=()=>navigate('pages',button.dataset.edit));
}
async function friendlyPageEditor(route='pages'){
  loading();let isNew=state.editId==='new';let row=isNew?{slug:'',title_en:'',title_zh:'',description_en:'',description_zh:'',status:'draft'}:(await query('pages','*',{eq:{id:state.editId}}))[0];if(!row)return navigate('pages');const draftKey=`cms-page-draft-${row.id||'new'}`,localDraft=JSON.parse(localStorage.getItem(draftKey)||'null');if(localDraft)row={...row,...localDraft};
  let sections=isNew?[]:await query('page_sections','*',{eq:{page_id:row.id},order:'sort_order'});if(localDraft?._sections)sections=localDraft._sections;row._cmsDraftOnly=!isNew;const helpRoute=route==='home'||route==='about'?route:null;
  const render=()=>{const lang=state.lang,preview=livePageUrl(row.slug||route);document.querySelector('#content').innerHTML=head(isNew?'New Page':`Edit ${row.title_en}`,'Current website content is shown below. Drafts stay private until Publish.')+(helpRoute?howToBox(helpRoute):'')+workflowBar(preview)+`<p class="save-status" data-save-status aria-live="polite"></p><form id="friendly-page-form" class="editor"><div class="editor-main"><section class="panel"><div class="panel-heading"><h2>Page content</h2><span class="pill ${row.status}">${row.status}</span></div>${languageTabs()}${field('Page title',`title_${lang}`,row[`title_${lang}`]||'','text','required')}${area('Description',`description_${lang}`,row[`description_${lang}`]||'')}</section><section class="panel"><div class="toolbar"><div><h2>Page sections</h2><p class="message">Drag the handle to reorder sections. Click Edit to change section content.</p></div><button class="btn" type="button" data-add-section>+ Add section</button></div><div class="section-list" id="friendly-section-list">${sections.length?sections.map(section=>{const sectionId=section.id||section._draftId;return `<div class="section-item" draggable="true" data-section="${sectionId}"><span class="drag-handle" title="Drag to reorder">⋮⋮</span><div><b>${esc(section[`title_${lang}`]||section.section_key)}</b><small class="pill">${esc(section.section_type)}</small></div><button class="btn" type="button" data-section-edit="${sectionId}">Edit</button></div>`}).join(''):'<div class="empty">No sections yet. Select Add section to begin.</div>'}</div></section></div><aside class="editor-side"><section class="panel"><h2>Page settings</h2>${field('Slug','slug',row.slug,'text','pattern="[a-z0-9-]+" required')}<div class="publish-note"><b>Draft</b><span>Private in the CMS</span><b>Published</b><span>Visible on the live website</span></div></section></aside></form>`;
    const form=document.querySelector('#friendly-page-form');const capture=()=>{captureFields(form,row,['title','description'],lang);row.slug=slugify(form.elements.slug.value)};bindFriendlyLanguageTabs(render,capture);
    const save=async status=>{capture();if(status==='draft'&&!isNew){localStorage.setItem(draftKey,JSON.stringify({...row,_sections:sections}));success('Draft saved privately in this browser. The published page remains live.');return}const payload={...row,status,published_at:status==='published'?new Date().toISOString():row.published_at||null,updated_by:state.profile.user_id};delete payload.id;delete payload.created_at;delete payload.updated_at;delete payload._cmsDraftOnly;delete payload._sections;try{const saved=await saveRow('pages',payload,isNew?null:row.id);row={...row,...saved};if(status==='published'&&!isNew){for(const section of sections){const sectionPayload={...section,page_id:saved.id};delete sectionPayload.id;delete sectionPayload._draftId;delete sectionPayload.created_at;delete sectionPayload.updated_at;const request=section.id?supabase.from('page_sections').update(sectionPayload).eq('id',section.id):supabase.from('page_sections').insert(sectionPayload);const{error}=await request;if(error)throw error}}isNew=false;row._cmsDraftOnly=true;state.editId=saved.id;if(status==='published')localStorage.removeItem(draftKey);success(status==='published'?'Page published. Refresh Preview to see the live update.':'Draft saved. It is not visible to visitors.');render()}catch(error){toast(error.message,true)}};
    document.querySelector('[data-action="draft"]').onclick=()=>save('draft');document.querySelector('[data-action="publish"]').onclick=()=>save('published');document.querySelector('[data-action="cancel"]').onclick=()=>navigate(route==='pages'?'pages':'dashboard');document.querySelector('[data-action="edit"]').onclick=()=>form.elements[`title_${lang}`].focus();
    document.querySelector('[data-add-section]').onclick=()=>openFriendlySectionModal(null,row,sections,render);document.querySelectorAll('[data-section-edit]').forEach(button=>button.onclick=()=>openFriendlySectionModal(sections.find(section=>(section.id||section._draftId)===button.dataset.sectionEdit),row,sections,render));
    bindDragList(document.querySelector('#friendly-section-list'),async ids=>{sections.sort((a,b)=>ids.indexOf(a.id||a._draftId)-ids.indexOf(b.id||b._draftId));sections.forEach((section,index)=>section.sort_order=index);if(isNew){for(const section of sections)if(section.id)await supabase.from('page_sections').update({sort_order:section.sort_order}).eq('id',section.id)}success(isNew?'Section order saved.':'Section order staged. Save Draft or Publish to keep it.')});
  };render();
}

