function guide(){document.querySelector('#content').innerHTML=head('Help & Guide','A beginner-friendly workflow for safely updating the website.')+`<div class="guide-grid"><section class="panel guide-steps"><h2>Publish your first change</h2><ol><li><b>Choose a menu page.</b><span>Home, About, Services and Work contain the main website content.</span></li><li><b>Click Edit.</b><span>The fields already contain the current website text.</span></li><li><b>Complete both language tabs.</b><span>Use English and 中文（简体） before publishing.</span></li><li><b>Save Draft.</b><span>Keep unfinished work private while you review it.</span></li><li><b>Preview.</b><span>Open the public destination in a new tab.</span></li><li><b>Publish.</b><span>The live website reads the newest published Supabase content immediately.</span></li></ol></section><section class="panel"><h2>Images</h2><p>Upload JPG, PNG, WebP or AVIF files smaller than 10 MB. The CMS optimizes normal JPG and PNG uploads to WebP.</p><h2>Safe editing tips</h2><p>Keep URL slugs lowercase. Do not publish empty Chinese fields. Use Draft whenever content still needs review.</p><h2>Need to undo?</h2><p>Owner can inspect Activity Log and restore supported previous page or project versions.</p></section></div>`}

async function renderRoute(){parseRoute();document.querySelectorAll('[data-route]').forEach(a=>a.classList.toggle('active',a.dataset.route===state.route));const label=document.querySelector('.topbar .eyebrow');if(label)label.textContent=titles[state.route];try{if(state.route==='dashboard')await dashboard();else if(['pages','home','about'].includes(state.route))await friendlyPages(state.route);else if(state.route==='services')await friendlyServices();else if(state.route==='projects')await friendlyProjects();else if(state.route==='media')await friendlyMedia();else if(['theme','footer','settings','navigation','seo'].includes(state.route))await simpleSettings(state.route);else if(state.route==='users')await users();else if(state.route==='activity')await activity();else if(state.route==='languages')languages();else if(state.route==='guide')guide()}catch(error){console.error(error);document.querySelector('#content').innerHTML=head('Unable to load','The CMS received a database error.')+`<div class="danger-note">${esc(error.message)}</div>`}}

async function start(){if(!configured)return setupView();const {data}=await supabase.auth.getSession();state.session=data.session;if(!state.session)return authView();if(!await loadProfile())return authView();parseRoute();shell()}
window.addEventListener('hashchange',()=>{if(state.session)renderRoute()});
if(supabase)supabase.auth.onAuthStateChange(async(event,session)=>{state.session=session;if(event==='SIGNED_OUT'){state.profile=null;authView()}else if(event==='SIGNED_IN'&&!state.profile){if(await loadProfile()){parseRoute();shell()}}});
start();

let lastActivity=Date.now();['pointerdown','keydown','scroll'].forEach(event=>window.addEventListener(event,()=>{lastActivity=Date.now()},{passive:true}));
setInterval(()=>{if(state.session&&Date.now()-lastActivity>30*60*1000)supabase?.auth.signOut()},60*1000);
